#!/usr/bin/env python3
"""apply_boss_variants.py — inject boss alt-shift variant portraits a1006-a1012 (raw base64) into assets/assets.json."""
import json,os,sys
root=os.path.dirname(os.path.abspath(__file__))
ap=os.path.join(root,"assets/assets.json")
if not os.path.exists(ap): sys.exit("[apply] assets/assets.json not found")
a=json.load(open(ap))
a.update({"a1006": "", "a1007": "", "a1008": "", "a1009": "", "a1010": "", "a1011": "", "a1012": ""})
json.dump(a,open(ap,"w"))
print("[apply] wrote boss variant portraits a1006-a1012")
